#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.frt[(b)];c;c=a.nxt[c])
#define Clear(a,b) memset(a,(b),sizeof(a))
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ; 
}
const int N=5e5+5;
struct Graph{int frt[N],nxt[N],des[N],cnt;
	inline void ins(int u,int v){des[++cnt]=v;nxt[cnt]=frt[u];frt[u]=cnt;}}a;
struct Tarjan{int low,dfn;bool isg;}q[N];int dep,ch,Rt,vis[N];int n,Time,mx;
long long ans2;int num0,num1,ans1,grp;
void tarjan(int u)
{
	q[u].dfn=q[u].low=++dep; grep(a,u,i)
	{
		int v=a.des[i];if(!q[v].dfn)
		{
			tarjan(v);q[u].low=min(q[u].low,q[v].low);
			if(q[v].low>=q[u].dfn&&u!=Rt)q[u].isg=1;if(u==Rt)ch++;
		}
		q[u].low=min(q[u].low,q[v].dfn);
	}
}
void dfs(int u)
{
	
	vis[u]=grp;num0++;grep(a,u,i)
	{
		int v=a.des[i];
		if(q[v].isg&&vis[v]!=grp)num1++,vis[v]=grp;
		if(!vis[v])dfs(v);
	}
}

inline void Main()
{
	Clear(q,0);Clear(a.frt,0);Clear(a.des,0);
	a.cnt=ans1=grp=mx=0;ans2=1;Clear(vis,0);Clear(a.nxt,0);
	rep(1,n,i){int x=read(),y=read();a.ins(x,y);a.ins(y,x);mx=max(mx,max(x,y));}
	rep(1,mx,i)if(!q[i].dfn){dep=ch=0,tarjan(Rt=i);if(ch>1)q[i].isg=1;}
	rep(1,mx,i)if(!q[i].isg&&!vis[i])
	{
		num0=num1=0;++grp;dfs(i);
		if(!num1)ans1+=2,ans2=ans2*1ll*(num0-1)*num0/2;
		if(num1==1)ans1++,ans2=ans2*1ll*num0;
	}
	printf("Case %d: %d %lld\n",Time,ans1,ans2);
}
int main(){while(n=read())Time++,Main();return 0;}
